/*
  Design system for minimalist monochrome forum layout
  ---------------------------------------------------
  - Colors and typography are derived from the provided palette and image.
  - Layout emphasizes negative space, neutral tones, and clean lines.
*/

:root {
  /* Color palette */
  --color-primary-900: #000000; /* Header background, primary text on light */
  --color-primary-800: #111111; /* Main body text */

  --color-bg-page: #F6F5F1;     /* Off-white page background */
  --color-bg-surface: #FFFFFF;  /* Card and surface background */

  --color-border-subtle: #E0DFDC; /* Card borders, dividers */
  --color-border-muted: #CFCFCF; /* Avatar placeholder, lighter borders */

  --color-text-main: #111111;   /* Primary text */
  --color-text-muted: #777777;  /* Metadata, secondary text */
  --color-text-inverse: #F6F5F1; /* Text on dark header */

  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #1565C0;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, Arial, sans-serif;
  --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
  --font-code: 'Source Code Pro', Menlo, Monaco, Consolas, 'Courier New', monospace;

  --font-size-h1: 30px; /* 28–32px range */
  --font-size-h2: 23px; /* 22–24px range */
  --font-size-h3: 19px; /* 18–20px range */
  --font-size-body: 15px; /* 14–16px range */
  --font-size-small: 12px; /* 12–13px range */

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (4px, 8px, 16px, 24px, 32px, 48px, 64px) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Component sizing */
  --header-height: 48px;
  --content-max-width: 960px;

  --radius-xs: 2px;
  --radius-sm: 3px;
  --radius-full: 999px;

  --transition-fast: 120ms ease-out;
}

/* Global reset-ish styles kept minimal to preserve the clean look */
* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-bg-page);
  -webkit-font-smoothing: antialiased;
}

.site {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* Header */

.site-header {
  background-color: var(--color-primary-900);
  color: var(--color-text-inverse);
}

.header-inner {
  max-width: 1200px;
  margin: 0 auto;
  height: var(--header-height);
  padding: 0 var(--space-4);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left,
.header-right {
  display: flex;
  align-items: center;
}

/* Primary navigation */

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  gap: var(--space-4); /* 24–32px horizontal spacing between items */
}

.primary-nav-link {
  position: relative;
  display: inline-block;
  padding: 2px 0; /* visually light, text-only treatment */
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.02em;
  text-decoration: none;
  color: var(--color-text-inverse);
}

.primary-nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -4px;
  width: 0;
  height: 1px;
  background-color: var(--color-text-inverse);
  transition: width var(--transition-fast);
}

.primary-nav-link:focus-visible,
.primary-nav-link:hover {
  outline: none;
}

.primary-nav-link:hover::after,
.primary-nav-link:focus-visible::after {
  width: 100%;
}

/* Header right: search icon and user menu */

.header-right {
  gap: var(--space-4);
}

.nav-icon {
  display: inline-block;
}

/* Minimal magnifying-glass-like search icon (visual only) */
.nav-icon-search {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 1px solid var(--color-text-inverse);
  position: relative;
}

.nav-icon-search::after {
  content: '';
  position: absolute;
  width: 8px;
  height: 1px;
  background-color: var(--color-text-inverse);
  transform-origin: left center;
  transform: rotate(40deg);
  right: -4px;
  bottom: 1px;
}

/***************************
 * User avatar & dropdown  *
 ***************************/

.user-menu {
  position: relative;
}

.user-avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1px solid var(--color-text-inverse);
  background-color: transparent;
  padding: 0;
  margin: 0;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: var(--color-text-inverse);
  font-family: var(--font-heading);
  font-size: 12px;
}

.user-avatar:focus-visible {
  outline: 2px solid var(--color-text-inverse);
  outline-offset: 2px;
}

.user-avatar-initials {
  line-height: 1;
}

.user-menu-dropdown {
  position: absolute;
  right: 0;
  top: calc(100% + var(--space-2));
  min-width: 160px;
  margin: 0;
  padding: var(--space-2) 0;
  list-style: none;
  background-color: var(--color-bg-surface);
  border: 1px solid var(--color-border-subtle);
  border-radius: var(--radius-xs);
  display: none;
  z-index: 10;
}

.user-menu-item {
  margin: 0;
}

.user-menu-link {
  display: block;
  padding: var(--space-2) var(--space-4);
  font-size: 13px;
  text-decoration: none;
  color: var(--color-text-main);
}

.user-menu-link:hover,
.user-menu-link:focus-visible {
  background-color: var(--color-bg-page);
  outline: none;
}

/* Show dropdown on hover or keyboard focus within */
.user-menu:hover .user-menu-dropdown,
.user-menu:focus-within .user-menu-dropdown {
  display: block;
}

/* Main layout */

.site-main {
  flex: 1 0 auto;
  max-width: var(--content-max-width);
  width: 100%;
  margin: 0 auto;
  padding: var(--space-7) var(--space-4) var(--space-7);
}

/* Optional shell for pages that want the large top gap seen in the design */

.content-shell {
  margin-top: var(--space-6);
}

/* Card / post list styles replicating the visible forum threads */

.post-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-4); /* 24–32px separation between cards */
}

.post-card {
  background-color: var(--color-bg-surface);
  border: 1px solid var(--color-border-subtle);
  border-radius: 0; /* sharp corners as in the design */
  padding: var(--space-5);
}

.post-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--space-3);
}

.post-card-author {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.post-card-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background-color: var(--color-border-muted);
  flex-shrink: 0;
}

.post-card-meta {
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

.post-card-body {
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
}

.post-card-title {
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  font-weight: var(--font-weight-medium);
  margin: 0 0 var(--space-2);
}

.post-card-text {
  margin: 0;
}

/* Vertical ellipsis icon (for card options) */

.post-card-menu {
  width: 16px;
  text-align: center;
  font-size: 16px;
  line-height: 1;
  color: var(--color-text-main);
}

.post-card-menu::before {
  content: '\22EE'; /* Unicode vertical ellipsis */
}

/* Footer */

.site-footer {
  flex-shrink: 0;
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-bg-page);
}

.footer-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: var(--space-4) var(--space-4) var(--space-5);
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
}

.footer-nav-item {
  font-size: var(--font-size-small);
}

.footer-nav-link {
  text-decoration: none;
  color: var(--color-text-muted);
}

.footer-nav-link:hover,
.footer-nav-link:focus-visible {
  color: var(--color-text-main);
  outline: none;
}

/* Utilities */

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

@media (max-width: 768px) {
  .header-inner {
    padding-inline: var(--space-3);
  }

  .primary-nav-list {
    gap: var(--space-3);
  }

  .site-main {
    padding-inline: var(--space-3);
  }

  .post-card {
    padding: var(--space-4);
  }
}
